const token = $input.first().json.access_token;
const baseUrl = $input.first().json.base_url ?? 'https://api13.toconline.pt';
const body = $('Webhook').first().json.body;
const invoices = body.invoices ?? [];

return invoices.map(inv => ({
  json: {
    access_token: token,
    base_url: baseUrl,
    isoflow_id: inv.id,
    supplier_name: inv.supplier_name,
    supplier_nif: inv.supplier_nif,
    invoice_number: inv.invoice_number,
    invoice_date: inv.invoice_date,
    subtotal: inv.subtotal,
    vat_rate: inv.vat_rate,
    vat_amount: inv.vat_amount,
    total: inv.total,
    description: inv.description,
    currency: inv.currency ?? 'EUR'
  }
}));

const items = $input.all();
const results = items.map(item => {
  const body = item.json;
  return {
    isoflow_id: body.external_reference ?? null,
    fc_id: body.id ? String(body.id) : null,
    fc_number: body.document_number ?? body.number ?? null,
    success: !!body.id
  };
});

return [{ json: { results } }];
